const item = $input.item.json;

// ============================================================
// 🛡️ MODO PERMISIVO: si OpenAI falla (timeout, invalid_image_url,
// rate limit, etc.), DEJAR PASAR como válido para no perder ventas.
// ============================================================

// Detectar si vino un ERROR de OpenAI (Continue On Fail activado)
const tieneError = item.error || 
                   item.errorMessage || 
                   (item.code && item.code.toString().includes('invalid_image')) ||
                   (item.statusCode && item.statusCode >= 400);

if (tieneError) {
    return {
        json: {
            es_valido: true,
            razon: "✅ Auto-validado por error técnico de IA (timeout/imagen no descargable). Se asume válido por filosofía permisiva.",
            monto: [PRECIO_BASE],
            metodo_pago: "OTRO",
            receptor_detectado: "no verificado por error técnico",
            mensaje_razon_humano: "Comprobante aceptado.",
            _auto_validado: true,
            _error_original: item.errorMessage || item.error || "error desconocido"
        }
    };
}

// ============================================================
// FLUJO NORMAL: HTTP Request a OpenAI devolvió choices[0].message.content
// ============================================================
if (item.choices && item.choices[0] && item.choices[0].message) {
    const content = item.choices[0].message.content;

    // Caso 1: content es objeto (response_format json_object lo parseó)
    if (typeof content === 'object' && content !== null) {
        return {
            json: {
                es_valido: content.es_valido === true,
                razon: content.razon || "Sin razón",
                monto: content.monto || 0,
                metodo_pago: content.metodo_pago || "OTRO",
                receptor_detectado: content.receptor_detectado || "no detectado",
                mensaje_razon_humano: content.mensaje_razon_humano || "Por favor reenvía el comprobante del pago por Yape o Plin al [NUMERO_PAGO] a nombre de [TITULAR_CUENTA]."
            }
        };
    }

    // Caso 2: content es string JSON, hay que parsearlo
    let texto = content.toString().trim().replace(/```json|```/g, "").trim();
    const matchJSON = texto.match(/\{[\s\S]*\}/);
    if (matchJSON) texto = matchJSON[0];

    try {
        const datos = JSON.parse(texto);
        return {
            json: {
                es_valido: datos.es_valido === true,
                razon: datos.razon || "Sin razón",
                monto: datos.monto || 0,
                metodo_pago: datos.metodo_pago || "OTRO",
                receptor_detectado: datos.receptor_detectado || "no detectado",
                mensaje_razon_humano: datos.mensaje_razon_humano || "Por favor reenvía un comprobante válido."
            }
        };
    } catch (e) {
        // Si falla el parseo del JSON de OpenAI, también dejamos pasar (filosofía permisiva)
        return {
            json: {
                es_valido: true,
                razon: "✅ Auto-validado por error de parseo IA: " + e.message,
                monto: [PRECIO_BASE],
                metodo_pago: "OTRO",
                receptor_detectado: "error de parseo",
                mensaje_razon_humano: "Comprobante aceptado.",
                _auto_validado: true
            }
        };
    }
}

// ============================================================
// Fallback: estructura inesperada → también dejamos pasar
// ============================================================
return {
    json: {
        es_valido: true,
        razon: "✅ Auto-validado por estructura inesperada de respuesta",
        monto: [PRECIO_BASE],
        metodo_pago: "OTRO",
        receptor_detectado: "estructura inesperada",
        mensaje_razon_humano: "Comprobante aceptado.",
        _auto_validado: true,
        _debug_keys: Object.keys(item).join(', ')
    }
};

// 1. Obtenemos los mensajes
const data = $input.item.json;
const mensajes = data.payload || [];

// 2. Ordenamos del más antiguo al más reciente (Vital para la memoria)
mensajes.sort((a, b) => a.created_at - b.created_at);

let historial = "";

// 3. Formateamos para la IA
mensajes.forEach(msg => {
    let sender = "";

    // 0 = Cliente, 1 = Agente/Bot
    if (msg.message_type === 0) {
        sender = "👤 [CLIENTE]";
    } else if (msg.private) {
        sender = "⚙️ [SISTEMA]";
    } else {
        sender = "🤖 [CARLOS - TÚ]";
    }

    const texto = msg.content;

    if (texto && texto.toString().trim() !== "") {
        historial += `${sender}: ${texto}\n`;
    }
});

return {
    json: {
        chat_history: historial
    }
};

const item = $input.item.json;
let textoIA = "";

// ============================================================
// Buscar el texto en TODAS las ubicaciones posibles
// ============================================================

// Caso 1: estructura nueva langchain.openAi
if (item.message && typeof item.message.content === 'string') {
    textoIA = item.message.content;
}
// Caso 2: estructura con output array
else if (item.output && Array.isArray(item.output) && item.output[0]?.content?.[0]?.text) {
    textoIA = item.output[0].content[0].text;
}
// Caso 3: si content es directamente string
else if (typeof item.content === 'string') {
    textoIA = item.content;
}
// Caso 4: si message.content es objeto
else if (item.message && typeof item.message.content === 'object') {
    textoIA = JSON.stringify(item.message.content);
}
// Caso 5: si todo el item ES la respuesta
else if (typeof item === 'object' && item.intencion && item.respuesta_ia) {
    return {
        json: {
            intencion: item.intencion,
            respuesta_ia: typeof item.respuesta_ia === 'string'
                ? item.respuesta_ia
                : JSON.stringify(item.respuesta_ia)
        }
    };
}
// Fallback
else {
    textoIA = JSON.stringify(item);
}

// ============================================================
// Limpiar el texto
// ============================================================

textoIA = textoIA.toString().trim();

// Quitar markdown ```json ... ``` si vino con eso
textoIA = textoIA.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

// ============================================================
// Parsear JSON
// ============================================================

let parsed;
try {
    parsed = JSON.parse(textoIA);
} catch (e) {
    // Si no es JSON, devolver como respuesta plana
    return {
        json: {
            intencion: 'OTRO',
            respuesta_ia: textoIA
        }
    };
}

// ============================================================
// Devolver respuesta
// ============================================================

return {
    json: {
        intencion: parsed.intencion || 'OTRO',
        respuesta_ia: parsed.respuesta_ia || textoIA
    }
};

// Extraer email — versión PERMISIVA: solo busca @ y se lo manda a Supabase
const config = $('⚙️ CONFIGURAR TODO AQUÍ').item.json;
let mensaje = (config.cliente_mensaje || '').toString().trim();

// Limpieza básica: quitar caracteres invisibles
mensaje = mensaje
  .replace(/[\u200B-\u200D\uFEFF]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

// Buscar cualquier "cosa@cosa" — sin validar TLD ni nada estricto
const match = mensaje.match(/(\S+@\S+)/);

if (match && match[1]) {
  // Limpiar puntuación al final por si quedó pegada
  let email = match[1].toLowerCase().replace(/[.,;:!?]+$/, '').trim();

  return [{
    json: {
      email_valido: true,
      email: email,
      mensaje_original: config.cliente_mensaje
    }
  }];
}

// No hay @ → email inválido
return [{
  json: {
    email_valido: false,
    email: null,
    mensaje_original: config.cliente_mensaje
  }
}];

const config = $('⚙️ CONFIGURAR TODO AQUÍ').item.json;
const hashes = $input.first().json;

// === LEER MONTO DE VISION (con fallback) ===
let monto = [PRECIO_BASE];
try {
  const visionData = $('🆕 Parser Vision (robusto)').item.json;
  if (visionData && visionData.monto) {
    monto = visionData.monto;
  }
} catch (e) {
  monto = [PRECIO_BASE];
}

// === LEER ctwa_clid CON .all() ===
let ctwaClid = null;
let debugInfo = 'inicio';

try {
  const ctwaItems = $('🔍 Buscar ctwa_clid').all();
  debugInfo = 'items_count_' + (ctwaItems ? ctwaItems.length : 'null');

  if (ctwaItems && ctwaItems.length > 0) {
    const firstJson = ctwaItems[0].json;
    debugInfo += '_type_' + (Array.isArray(firstJson) ? 'array' : typeof firstJson);

    if (Array.isArray(firstJson) && firstJson.length > 0) {
      ctwaClid = firstJson[0].ctwa_clid;
      debugInfo += '_from_array';
    } else if (firstJson && firstJson.ctwa_clid) {
      ctwaClid = firstJson.ctwa_clid;
      debugInfo += '_from_object';
    }
  }
} catch (e) {
  debugInfo = 'error_' + e.message;
  ctwaClid = null;
}

// === DATOS BASE ===
const telefono = config.telefono_cliente;
const pixelId = config.pixel_id;
const accessToken = config.capi_token;
const pageId = Number(config.page_id);

// 🔑 ID ESTABLE por compra: mismo cliente + mismo día = mismo id -> Facebook deduplica
const fecha = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
const orderId = 'ORDER_' + telefono + '_' + fecha;

// === ARMAR USER_DATA ===
const userData = {
  page_id: pageId,
  em: [hashes.email_hash],
  ph: [hashes.telefono_hash],
  fn: [hashes.nombre_hash],
  ln: [hashes.apellido_hash],
  country: [hashes.country_hash],
  external_id: [hashes.external_id_hash]
};

if (ctwaClid) {
  userData.ctwa_clid = ctwaClid;
}

// === PAYLOAD FINAL ===
const payload = {
  data: [{
    event_name: 'Purchase',
    event_time: Math.floor(Date.now() / 1000),
    event_id: 'purchase_' + telefono + '_' + fecha,
    action_source: 'business_messaging',
    messaging_channel: 'whatsapp',
    user_data: userData,
    custom_data: {
      currency: 'PEN',
      value: monto,
      content_name: '[NOMBRE_PRODUCTO_UPPER]',
      content_ids: ['[PRODUCTO_ID_PE_LARGO]'],
      content_type: 'product',
      contents: [{
        id: '[PRODUCTO_ID_PE_LARGO]',
        quantity: 1,
        item_price: monto
      }],
      order_id: orderId
    }
  }],
  access_token: accessToken
};

return [{
  json: {
    pixel_id: pixelId,
    payload: payload,
    debug_ctwa_clid: ctwaClid || 'NO ENCONTRADO',
    debug_info: debugInfo
  }
}];

