// ============================================================
// 🧠 PRE-PROCESADOR v3 (PERÚ — soles) — Solo calcula contexto
// ============================================================
// ⚠️ AJUSTA ESTAS CONSTANTES SEGÚN EL PRODUCTO:
//   PRECIO_BASE         = precio normal de venta (ej: 10)
//   PRECIO_RMK_15M      = precio remarketing 15 min (ej: 8)
//   PRECIO_RMK_60M      = precio remarketing 60 min (ej: 6)
//   PRECIO_RMK_180M     = precio remarketing 180 min (ej: 4)
//   PRECIO_ADICIONAL_OB = lo que se suma al combo (ej: 5)
//   PISO_REGATEO        = mínimo absoluto que acepta Carlos (ej: 6)
// ============================================================

const config = $('⚙️ CONFIGURAR TODO AQUÍ').item.json;
const body = $('When Executed by Recibidor').item.json.body || {};
const labels = body.labels || [];
const customAttrs = body.custom_attributes || body.meta?.sender?.custom_attributes || {};
const mensajeOriginal = (config.cliente_mensaje || '').toString();
const msgLower = mensajeOriginal.toLowerCase().trim();

// ============================================================
// 1️⃣ DETERMINAR PRECIO ACTUAL (en soles)
// ============================================================
const estadoRmk = customAttrs.estado_rmk || '';
let precioBase = [PRECIO_BASE];
if (estadoRmk === 'rmk_15m_[CATEGORIA_PRODUCTO]') precioBase = [PRECIO_RMK_15M];
else if (estadoRmk === 'rmk_60m_[CATEGORIA_PRODUCTO]') precioBase = [PRECIO_RMK_60M];
else if (estadoRmk === 'rmk_180m_[CATEGORIA_PRODUCTO]') precioBase = [PRECIO_RMK_180M];

// 🔑 PRIORIDAD: si el cliente menciona un precio en SU mensaje, ese MANDA
let precioMencionadoPorCliente = null;
const matchPrecio = msgLower.match(/(?:s\/\s*|\bsoles?\b\s*)(\d{1,3})|(\d{1,2})\s*(?:soles?|lucas?)\b/);
if (matchPrecio) {
  const num = parseInt(matchPrecio[1] || matchPrecio[2]);
  // Acepta regateos en rango [PISO_REGATEO, PRECIO_BASE + 20]
  if (num >= [PISO_REGATEO] && num <= [PRECIO_BASE] + 20) precioMencionadoPorCliente = num;
}

const precioCotizar = precioMencionadoPorCliente || precioBase;
const precioCombo = precioCotizar + [PRECIO_ADICIONAL_OB];

// ============================================================
// 2️⃣ ESTADO DEL CLIENTE
// ============================================================
const yaCompro = labels.includes('comprador');
const tocoMetodoPago = labels.includes('metodo_pago');
const tieneOBSi = labels.includes('ob_si');

let modoCliente = 'PROSPECTO';
if (yaCompro) modoCliente = 'COMPRADOR';
else if (tocoMetodoPago) modoCliente = 'PENDIENTE_PAGO';

// ============================================================
// 3️⃣ DETECTAR CATEGORÍA
// ============================================================
let categoria = 'OTRO';
const tieneAlguna = (palabras) => palabras.some(p => msgLower.includes(p));

if (tieneAlguna(['cuánto', 'cuanto', 'precio', 'cuesta', 'vale', 'pagar', 'costo']) || matchPrecio !== null) {
  categoria = 'PRECIO';
}
else if (tieneAlguna(['cuándo llega', 'cuando llega', 'cuándo recibo', 'cuando recibo',
                      'cuánto tarda', 'cuanto tarda', 'tiempo de entrega', 'inmediato', 'me llega'])) {
  categoria = 'ENTREGA';
}
else if (tieneAlguna(['garantía', 'garantia', 'cuánto dura', 'caduca', 'expira', 'mensualidad'])) {
  categoria = 'GARANTIA';
}
else if (tieneAlguna(['virtual', 'presencial', 'físico', 'fisico', 'qué incluye', 'que incluye',
                      'qué viene', 'que viene', 'qué es', 'que es', 'qué son', 'que son'])) {
  categoria = 'CONTENIDO';
}
else if (tieneAlguna(['cómo pago', 'como pago', 'métodos de pago', 'metodos de pago', 'formas de pago',
                      'donde pago', 'dónde pago', 'yape', 'plin'])) {
  categoria = 'METODOS_PAGO';
}
else if (msgLower.length < 25 && tieneAlguna(['hola', 'buenas', 'buen día', 'buenos días', 'buenas tardes'])) {
  categoria = 'SALUDO';
}
else if (msgLower.length < 15 && tieneAlguna(['ok', 'okey', 'okay', 'gracias', 'vale', 'listo',
                                                'perfecto', 'genial', 'bueno', 'dale', 'va'])) {
  categoria = 'ACUSE';
}
else if (tieneAlguna(['no me', 'no quiero', 'no puedo', 'no tengo', 'caro', 'mucho', 'pienso',
                      'después', 'despues', 'mañana', 'no por ahora', 'no gracias'])) {
  categoria = 'OBJECION';
}

// ============================================================
// 4️⃣ FORMATEAR PRECIOS LEGIBLES (soles)
// ============================================================
const fmt = (n) => 'S/ ' + n;

// ============================================================
// 5️⃣ URGENCIA
// ============================================================
const urgencia = (precioBase < [PRECIO_BASE])
  ? '⏰ Promo especial — últimos cupos al precio actual'
  : '🔥 Es precio de lanzamiento — sube esta semana';

// ============================================================
// 6️⃣ RETORNO
// ============================================================
return [{
  json: {
    modo_cliente: modoCliente,
    estado_rmk: estadoRmk || 'sin_remarketing',
    tiene_ob_si: tieneOBSi,
    precio_cotizar: precioCotizar,
    precio_str: fmt(precioCotizar),
    precio_combo: precioCombo,
    precio_combo_str: fmt(precioCombo),
    cliente_menciono_precio: precioMencionadoPorCliente !== null,
    precio_mencionado: precioMencionadoPorCliente,
    precio_mencionado_str: precioMencionadoPorCliente ? fmt(precioMencionadoPorCliente) : null,
    categoria_sugerida: categoria,
    urgencia_texto: urgencia,
    mensaje_cliente: mensajeOriginal
  }
}];

