// ============================================================
// CLASIFICADOR — versión Order Bump SÚPER PERMISIVA
// ============================================================
const MODO_TESTING = true;

const input = $input.first().json;
const body = input.body || {};
const messages = body.messages || [];
const lastMsg = messages[messages.length - 1] || {};
const labels = body.labels || [];

// ===== ¿Es imagen? =====
const esImagen = (lastMsg.content_type === 'image') ||
                 (lastMsg.attachments && lastMsg.attachments.length > 0 && lastMsg.attachments[0].file_type === 'image');

// ===== ¿Es respuesta a botón? — Detección robusta =====
let botonValue = null;
const contenidoTexto = (lastMsg.content || '').trim();

// Helper: normalizar texto (quitar emojis, lowercase, sin espacios)
function normalizar(texto) {
  return texto
    .replace(/[\u{1F300}-\u{1F9FF}]/gu, '')   // emojis principales
    .replace(/[\u{2600}-\u{27BF}]/gu, '')     // dingbats (✅ ❌ ⚡ etc.)
    .replace(/[\u{1F000}-\u{1FFFF}]/gu, '')   // suplementario
    .replace(/\uFE0F/g, '')                   // variation selectors
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

// FORMATO A: submitted_values en content_attributes (estándar WhatsApp)
if (lastMsg.content_attributes &&
    lastMsg.content_attributes.submitted_values &&
    lastMsg.content_attributes.submitted_values.length > 0) {
  botonValue = lastMsg.content_attributes.submitted_values[0].value;
}
// FORMATO B: el content trae directamente el value
else if (contenidoTexto === 'ob_si' || contenidoTexto === 'ob_no' || contenidoTexto.startsWith('pago_')) {
  botonValue = contenidoTexto;
}
// FORMATO C: matching por contenido normalizado
else {
  const normalizado = normalizar(contenidoTexto);

  // 🛒 Botones del Order Bump (detección PERMISIVA)
  if (normalizado === 'si' || normalizado === 'sí' || normalizado === 'yes') {
    botonValue = 'ob_si';
  } else if (normalizado === 'no') {
    botonValue = 'ob_no';
  }
  // 💳 Botones de método de pago
  else if (normalizado.includes('plin')) {
    botonValue = 'pago_plin';
  }
  else if (normalizado.includes('transferencia') || normalizado.includes('yape')) {
    botonValue = 'pago_yape';
  }
}

const esBoton = botonValue !== null;

// ===== ¿Es nuevo lead? =====
const esNuevo = MODO_TESTING
  ? !labels.includes('bienvenido')
  : input.is_new_attribution === true;

// ===== Clasificación final =====
let tipoMensaje = 'TEXTO_LIBRE';
if (esImagen) tipoMensaje = 'IMAGEN';
else if (esBoton) tipoMensaje = 'BOTON';
else if (esNuevo) tipoMensaje = 'AD';

return {
  json: {
    tipo_mensaje: tipoMensaje,
    boton_value: botonValue,
    es_imagen: esImagen,
    contenido_texto_recibido: contenidoTexto,
    contenido_normalizado: normalizar(contenidoTexto),
    es_nuevo: esNuevo,
    labels_actuales: labels,
    imagen_url: esImagen && lastMsg.attachments ? lastMsg.attachments[0].data_url : null
  }
};

// Buscar ctwa_clid, ad_id de mensajes + primer_contacto_at de contactos
const phone = $('⚙️ CONFIGURAR TODO AQUÍ').item.json.telefono_cliente;
const supaUrl = 'https://jquahxsesqcjakxkcneu.supabase.co';
const apiKey = 'sb_secret_lMhmTaKYyvdV3vHHOWmdzg_1N-coTRg';
const headers = { apikey: apiKey, Authorization: 'Bearer ' + apiKey };

let ctwa_clid = null, ad_id = null, ad_name = null, primer_contacto_at = null;

try {
  // 1. Buscar en mensajes: ctwa_clid y ad_id del primer mensaje con referral
  const msgs = await this.helpers.httpRequest({
    method: 'GET',
    url: supaUrl + '/rest/v1/mensajes?phone=eq.' + phone + '&ctwa_clid=not.is.null&select=ctwa_clid,ad_id&order=recibido_at.asc&limit=1',
    headers
  });
  if (Array.isArray(msgs) && msgs.length > 0) {
    ctwa_clid = msgs[0].ctwa_clid || null;
    ad_id = msgs[0].ad_id || null;
  }
} catch(e) {}

try {
  // 2. Buscar en contactos: primer_contacto_at
  const cont = await this.helpers.httpRequest({
    method: 'GET',
    url: supaUrl + '/rest/v1/contactos?phone=eq.' + phone + '&select=primer_contacto_at&limit=1',
    headers
  });
  if (Array.isArray(cont) && cont.length > 0) {
    primer_contacto_at = cont[0].primer_contacto_at || null;
  }
} catch(e) {}

return [{ json: {
  ...($input.first().json),
  atrib_ctwa_clid: ctwa_clid,
  atrib_ad_id: ad_id,
  atrib_primer_contacto_at: primer_contacto_at
} }];

const config = $('⚙️ CONFIGURAR TODO AQUÍ').item.json;
const hashes = $input.first().json;

// === LEER MONTO DE VISION (con fallback) ===
let monto = [PRECIO_BASE];
try {
  const visionData = $('🆕 Parser Vision (robusto)').item.json;
  if (visionData && visionData.monto) {
    monto = visionData.monto;
  }
} catch (e) {
  monto = [PRECIO_BASE];
}

// === LEER ctwa_clid ===
let ctwaClid = null;
try {
  const atribItems = $('📊 Buscar atribución').all();
  if (atribItems && atribItems.length > 0) {
    const firstJson = atribItems[0].json;
    if (firstJson && firstJson.atrib_ctwa_clid) {
      ctwaClid = firstJson.atrib_ctwa_clid;
    }
  }
} catch (e) {
  ctwaClid = null;
}

// === DATOS BASE ===
const telefono = config.telefono_cliente;
const pixelId = config.pixel_id;
const accessToken = config.capi_token;
const pageId = Number(config.page_id);

// 🔑 MISMO event_id que el CAPI tardío → Facebook deduplica
const fecha = new Date().toISOString().slice(0, 10);
const orderId = 'ORDER_' + telefono + '_' + fecha;

// === USER_DATA SIN email ===
const userData = {
  page_id: pageId,
  ph: [hashes.telefono_hash],
  fn: [hashes.nombre_hash],
  ln: [hashes.apellido_hash],
  country: [hashes.country_hash],
  external_id: [hashes.external_id_hash]
};

if (ctwaClid) {
  userData.ctwa_clid = ctwaClid;
}

// === PAYLOAD FINAL (sin em[]) ===
const payload = {
  data: [{
    event_name: 'Purchase',
    event_time: Math.floor(Date.now() / 1000),
    event_id: 'purchase_' + telefono + '_' + fecha,
    action_source: 'business_messaging',
    messaging_channel: 'whatsapp',
    user_data: userData,
    custom_data: {
      currency: 'PEN',
      value: monto,
      content_name: '[NOMBRE_PRODUCTO_UPPER]',
      content_ids: ['[PRODUCTO_ID_PE_LARGO]'],
      content_type: 'product',
      contents: [{
        id: '[PRODUCTO_ID_PE_LARGO]',
        quantity: 1,
        item_price: monto
      }],
      order_id: orderId
    }
  }],
  access_token: accessToken
};

return [{
  json: {
    pixel_id: pixelId,
    payload: payload,
    _capi_phase: 'EARLY_no_email',
    debug_ctwa_clid: ctwaClid || 'NO ENCONTRADO'
  }
}];
